import { describe, expect, it } from 'vitest';
import { redactString } from './redaction.js';

describe('redactString (Google API key)', () => {
  it('redacts an AIza-style Google API key embedded in text', () => {
    const secret = 'AIzaSyD4c9f8g7h6j5k4l3m2n1p0q9r8s7t6u5v';
    const result = redactString(`google_api_key=${secret}`);
    expect(result).not.toContain(secret);
    expect(result).toContain('[REDACTED]');
  });

  it('leaves ordinary text untouched', () => {
    const message = 'Deploy succeeded in 4200ms.';
    expect(redactString(message)).toBe(message);
  });
});
